//	&EmpCod = EmpCod
//	&OutsdtJaspiImpressao_out.EmpWebBaseUrl = EmpDirVir + 'appjaspi/app/JASPI_IMP'+trim(str(&Versao)) + '.rar'
//	Exit 
//When none
//	&OutsdtJaspiImpressao_out.EmpStsMsg = 'ERRO DE EMPRESA, NAO LOCALIZADA'
//	return
//EndFor


For each Order EmpCod, MonRandon
	Where MonRandon = &monRandon //localiza monitor
	where MonSts = Status_Pdv.INSTALADO
	Where MonTip <> TipoApp.BI

	&monCod 	= MonCod

	&EmpCod = EmpCod
	&OutsdtJaspiImpressao_out.EmpStsMsg = EmpRaz

	//if &EmpImpVer <> &Versao
//	&OutsdtJaspiImpressao_out.sts = 'E998'
//	&OutsdtJaspiImpressao_out.msg = 'ERRO DE VERSAO, NECESSARIO UTILIZACAO VERSAO: ' + trim(str(&Versao))
//	&OutsdtJaspiImpressao_out.EmpImpVer = &Versao
//	return
//Endif

	Exit 
When none
	&OutsdtJaspiImpressao_out.sts = 'E997'
	&OutsdtJaspiImpressao_out.msg = 'ERRO DE EMPRESA, NAO LOCALIZADA'
	return
EndFor


Do case
	Case &EmpTipSol = 'VERSAO'

	Case &EmpTipSol = 'PENDENTE'
		If &EmpCod > 0			
			&fiDtaIni = serverNow()
			For Each Order FIempCod, FIcod
				Where FIempCod = &EmpCod
				Where FIsts = 'P' //PENDENTE
				Where FIimpPC = &monCod //Nome do Monitor
				Where FiDtaIni.IsEmpty() or FiDtaIni.IsNull() or FiDtaIni <= &fiDtaIni

				&OutsdtJaspiImpressao_out.EmpFiCod = FIcod
				&OutsdtJaspiImpressao_out.EmpXmlImprimir = FirelInfAdi
				&OutsdtJaspiImpressao_out.EmpImpNom = FIimpNom //Nome da impressora
				&OutsdtJaspiImpressao_out.EmpImpTip = FIimpTip.ToString() //domTipoImpressora //MATRICIAL, CUPOM1, CUPOM2, ...
				&OutsdtJaspiImpressao_out.EmpRelNam = FIrelNam

				Do Case
					CAse FIrelNam = 'RELJAS124'//impressão MATRICIAL pedido 
						&OutsdtJaspiImpressao_out.sts = 'J200'
						&OutsdtJaspiImpressao_out.msg = 'IMPRIMINDO DOC. PEDIDO MATRICIAL: RELJAS124, PEDIDO: '+trim(str(FiPedCod))

						RELJAS124.Call(FIempCod, FiFilCod, FiPedCod, &SdtRELJAS124)
						&SdtRELJAS124.FiDtaEms = trim(FiDtaEms.ToFormattedString())
						&OutsdtJaspiImpressao_out.EmpXmlImprimir = &SdtRELJAS124.ToJson() //conteudo imprimir						

					CAse FIrelNam = 'RELJAS124_A' //IMPRESSAO COMANDA COZINHA
						&OutsdtJaspiImpressao_out.sts = 'J200'
						&OutsdtJaspiImpressao_out.msg =  'IMPRIMINDO DOC. COMANDA COZINHA: RELJAS124_A, PEDIDO: '+trim(str(FiPedCod))

						&SdtRELJAS124_A_Produtos.FromJson(FirelInfAdi)
						RELJAS124_A.Call(FIempCod, FiFilCod, FiPedCod, &SdtRELJAS124_A_Produtos, &SdtRELJAS124_A)
						&OutsdtJaspiImpressao_out.EmpXmlImprimir = &SdtRELJAS124_A.ToJson()

					CAse FIrelNam = 'RELJAS124_B' or FIrelNam = 'CREDRELJAS124_B'//IMPRESSAO TICKET
						&OutsdtJaspiImpressao_out.sts = 'J200'
						&OutsdtJaspiImpressao_out.msg = 'IMPRIMINDO DOC. PEDIDO TICKET: RELJAS124_B, PEDIDO: '+trim(str(FiPedCod))

						//&SdtRELJAS124_A_Produtos.FromJson(FirelInfAdi)
						RELJAS124_B.Call(FIempCod, FiFilCod, FiPedCod, FIrelNam, FiUsuCod, &SdtRELJAS124_A)						
						&OutsdtJaspiImpressao_out.EmpXmlImprimir = &SdtRELJAS124_A.ToJson()						
						&OutsdtJaspiImpressao_out.EmpRelNam = 'RELJAS124_B'

					CAse FIrelNam = 'RELJAS029_CUPOM' //SEPARACAO TICKET
						&OutsdtJaspiImpressao_out.sts = 'J200'
						&OutsdtJaspiImpressao_out.msg = 'IMPRIMINDO DOC. SEPARACAO TICKET: RELJAS029_CUPOM, PEDIDO: '+trim(str(FiPedCod))

						&SdtFiltros.FromJson(FirelInfAdi) //FITLROS

						RELJAS029_CUPOM_DIRETA.Call(FIempCod, FiFilCod, FiPedCod, FIrelNam, FiUsuCod, &SdtFiltros, &SdtRELJAS124_A)						
						&OutsdtJaspiImpressao_out.EmpXmlImprimir = &SdtRELJAS124_A.ToJson()

					CAse FIrelNam = 'RELJAS057' or FIrelNam = 'RELJAS057_0' //IMPRESSAO NFCe
						&OutsdtJaspiImpressao_out.sts = 'J200'
						&OutsdtJaspiImpressao_out.msg = 'IMPRIMINDO DOC. IMPRESSAO NFCe: RELJAS057, NOTA FISCAL: '+trim(str(FiNfeCod))

						RELJAS057.Call(FIempCod, FiFilCod, FiNfeCod, FIrelNam, FiUsuCod, &sdtRELJAS_XXX_NFe)

						&sdtRELJAS_XXX_NFe.imgCodBarras = FirelInfAdi //aproveitei campo nao usado						
						&OutsdtJaspiImpressao_out.EmpXmlImprimir = &sdtRELJAS_XXX_NFe.ToJson()

					Case FIrelNam = 'RELJAS048_R10' //ETIQUETA INDAGRIL
						&OutsdtJaspiImpressao_out.sts = 'J200'
						&OutsdtJaspiImpressao_out.msg = 'IMPRIMINDO DOC. IMPRESSAO ETQUETA: RELJAS048_R10 '+trim(str(FiNfeCod))

					Case FIrelNam = 'RELJAS048_R05' //ETIQUETA GONDOLA
						&OutsdtJaspiImpressao_out.sts = 'J200'
						&OutsdtJaspiImpressao_out.msg = 'IMPRIMINDO DOC. IMPRESSAO ETQUETA: RELJAS048_006 '+trim(str(FiNfeCod))


						//					Case FIrelNam = 'LCTCAIXAPDV' //LANCAMENTO CAIXA
						//						&OutsdtJaspiImpressao_out.EmpStsMsg = 'IMPRIMINDO DOC. IMPRESSAO: LCTCAIXAPDV '+trim(str(FiNfeCod))
						//						
						//						&OutsdtJaspiImpressao_out.EmpFiCod = FIcod
						//						&OutsdtJaspiImpressao_out.EmpXmlImprimir = FirelInfAdi
						//						&OutsdtJaspiImpressao_out.EmpImpNom = FIimpTip
						//						&OutsdtJaspiImpressao_out.EmpRelNam = FIrelNam

						//					Case FIrelNam = 'LCTCARTAOPDV' //LANCAMENTO CARTAO
						//						
						//						&OutsdtJaspiImpressao_out.EmpStsMsg = 'IMPRIMINDO DOC. IMPRESSAO: LCTCARTAOPDV '+trim(str(FiNfeCod))
						//						&OutsdtJaspiImpressao_out.EmpFiCod = FIcod
						//						&OutsdtJaspiImpressao_out.EmpXmlImprimir = FirelInfAdi
						//						&OutsdtJaspiImpressao_out.EmpImpNom = FIimpTip
						//						&OutsdtJaspiImpressao_out.EmpRelNam = FIrelNam

						//					Case FIrelNam = 'FECHACAIXA' //RESUMO CAIXA
						//						
						//						&OutsdtJaspiImpressao_out.EmpStsMsg = 'IMPRIMINDO DOC. IMPRESSAO: FECHACAIXA '+trim(str(FiNfeCod))
						//						&OutsdtJaspiImpressao_out.EmpFiCod = FIcod
						//						&OutsdtJaspiImpressao_out.EmpXmlImprimir = FirelInfAdi
						//						&OutsdtJaspiImpressao_out.EmpImpNom = FIimpTip
						//						&OutsdtJaspiImpressao_out.EmpRelNam = FIrelNam

						//					Case FIrelNam = 'HISTORICOCLIENTE' //HISTORICO CLIENTE
						//						
						//						&OutsdtJaspiImpressao_out.EmpStsMsg = 'IMPRIMINDO DOC. IMPRESSAO HISTORICO: HISTORICOCLIENTE '+trim(str(FiNfeCod))
						//						&OutsdtJaspiImpressao_out.EmpFiCod = FIcod
						//						&OutsdtJaspiImpressao_out.EmpXmlImprimir = FirelInfAdi
						//						&OutsdtJaspiImpressao_out.EmpImpNom = FIimpTip
						//						&OutsdtJaspiImpressao_out.EmpRelNam = FIrelNam

						//					Case FIrelNam = 'TEF_CAPPTA_C' //COMPROVANTE DO TEF CAPPTA
						//					
						//						&OutsdtJaspiImpressao_out.EmpStsMsg = 'IMPRIMINDO DOC. TEF: TEF_CAPPTA '+trim(str(FiNfeCod))
						//						&OutsdtJaspiImpressao_out.EmpFiCod = FIcod
						//						&OutsdtJaspiImpressao_out.EmpXmlImprimir = FirelInfAdi  
						//						&OutsdtJaspiImpressao_out.EmpImpNom = FIimpTip
						//						&OutsdtJaspiImpressao_out.EmpRelNam = FIrelNam

						//					Case FIrelNam = 'TEF_COMPROVANTE' or FIrelNam = 'TEF_COMPROVANTE_C' or FIrelNam = 'TEF_COMPROVANTE_E'//COMPROVANTE DO TEF
						//						
						//						&OutsdtJaspiImpressao_out.EmpStsMsg = 'IMPRIMINDO DOC. TEF: TEF_COMPROVANTE '+trim(str(FiNfeCod))
						//						&OutsdtJaspiImpressao_out.EmpFiCod = FIcod
						//						&OutsdtJaspiImpressao_out.EmpXmlImprimir = FirelInfAdi
						//						&OutsdtJaspiImpressao_out.EmpImpNom = FIimpTip
						//						&OutsdtJaspiImpressao_out.EmpRelNam = FIrelNam
					otherwise
						&OutsdtJaspiImpressao_out.sts = 'E996'
						&OutsdtJaspiImpressao_out.msg = 'IMPRESSAO NAO LOCALIZADA'
				EndCase
			When none
				&OutsdtJaspiImpressao_out.sts = 'J201'
				&OutsdtJaspiImpressao_out.msg = 'Nenhum documento a ser impresso'
			EndFor
		Endif


	Case &EmpTipSol = 'FINALIZA'

		For Each Order FIempCod, FIcod
			Where FIempCod = &EmpCod
			Where FIcod = &FIcod
			FIsts = 'F'

			&OutsdtJaspiImpressao_out.sts = 'J200'
			&OutsdtJaspiImpressao_out.msg = 'SUCESSO'
			Exit
		EndFor
		Commit
EndCase
